import{_ as a,c as o,o as r,ae as p}from"./chunks/framework.BvcDoAct.js";const B=JSON.parse('{"title":"Novel Core","description":"","frontmatter":{},"headers":[],"relativePath":"zh-cn/Management2Extra/01_TalkAboutBMSG/01_NovelCore.md","filePath":"zh-cn/Management2Extra/01_TalkAboutBMSG/01_NovelCore.md"}'),t={name:"zh-cn/Management2Extra/01_TalkAboutBMSG/01_NovelCore.md"};function S(l,e,n,h,i,s){return r(),o("div",null,[...e[0]||(e[0]=[p('<p>Talk about BMSG - 01</p><h1 id="novel-core" tabindex="-1">Novel Core <a class="header-anchor" href="#novel-core" aria-label="Permalink to &quot;Novel Core&quot;">​</a></h1><h3 id="创造文化-这件事正以肉眼可见的形式日复一日地成为现实" tabindex="-1">“创造文化”这件事正以肉眼可见的形式日复一日地成为现实 <a class="header-anchor" href="#创造文化-这件事正以肉眼可见的形式日复一日地成为现实" aria-label="Permalink to &quot;“创造文化”这件事正以肉眼可见的形式日复一日地成为现实&quot;">​</a></h3><p><em>Novel Core：2001年1月18日出生，东京都出身</em><br><br><br> ————BMSG正处于为日本音乐行业带来各种变革的过程中，作为从成立之初就在籍的Novel Core，你是如何切身感受到的？</p><p>并不是说过去日本音乐行业的体系是好还是不好，我认为作为代表的SKY-HI，一直以来秉持着“希望BMSG能够增加‘正确答案’的数量，并提出新的标准”这样的立场走过了四年多。我在各种场合都能切实感受到，我们正在建立一种体系，让那些从既有音乐行业中溢出、或感到不适的人，也能够自在地开展活动。比如在「D.U.N.K.Showcase」中实现跨事务所的合作，BE:FIRST在国内外以各种形式展开联动，我们这些个人艺人也能进行跨越类型壁垒的活动。从跨越各种边界这一点来看，我觉得BMSG在日本音乐圈是相当少见的存在。</p><p>————你觉得BMSG有哪些变化？</p><p>根本的立场和心态设定完全没有改变，但可以说环境发生了很大的变化。从最初由日高先生亲自管理一切开始，如今已经发展成拥有众多员工的公司，作为伙伴的艺人也包括TRAINEE在内大幅增加。我觉得日高先生所说的“创造文化”，正以看得见的形式，一天天变成现实。</p><p>————最近，有没有对日高先生印象深刻的地方？</p><p>在「THE FIRST」期间，我第一次看到日高先生没有余裕的样子。那时候无论精神还是身体上，他都处于被逼到极限的状态，但现在我能明显感觉到，他在身心上逐渐有了余裕地面对工作。我们两个人聊天时，以前常常会聊公司的未来，而最近则经常只是聊些无关紧要的事情，不知不觉就过去一两个小时，这对我来说是件非常开心的事。</p><h3 id="bmsg汇聚了只有在这里才能发挥真正实力的成员" tabindex="-1">BMSG汇聚了只有在这里才能发挥真正实力的成员 <a class="header-anchor" href="#bmsg汇聚了只有在这里才能发挥真正实力的成员" aria-label="Permalink to &quot;BMSG汇聚了只有在这里才能发挥真正实力的成员&quot;">​</a></h3><p>————你对BMSG最引以为傲的是什么？</p><p>日高先生说“要为没有归属的艺人创造归属”，而我正是那种没有归属的人之一。能够身处日高先生所打造的、适合自己的新标准之中，我感到非常开心。同时，我也觉得像我和日高先生一样，还有BE:FIRST、MAZZEL那样，在既有体系中找不到归属的人其实还有很多。或许也会有很多人无法被BMSG所创造的新标准所容纳，但能够参与到这样一种有可能为这些未来之星聚光的活动之中，这是我最自豪的地方。</p><p>————在“BMSG FES”这样所属艺人齐聚一堂的场合，这种感受会更强烈吗？</p><p>会的。今年“BMSG FES&#39;24”中BE:FIRST的部分，日高先生对成员说过“感觉你们如果不是通过‘THE FIRST’，可能很难通过其他选秀”，但这完全不是负面的意思，我觉得正是因为是BMSG，才汇聚了这些能够在这里发挥真正实力的成员。能有这么多艺人和工作人员怀着“登上这艘船把一切都释放出来”的想法聚集在一起，真的让我非常开心。再想到公司最初是没有任何员工、只有我和日高先生两个人开始的，就更加感慨万千。</p><p>————在“BMSG FES&#39;24”中演唱的《Name Tag》混音版本里，“说到流行明星就是ATS”这一句让我很触动。</p><p>我一直都非常想大声喊出Shota（Aile The Shota）的名字。他是我的挚友，也是我在BMSG里相处时间最长、联系最频繁的人。他真的总是在思考更长远的未来去进行活动，也正因为自己成为了活跃在主流舞台上的存在，所以他有着非常强烈的能量，希望去带动地下的伙伴们、掀起更大的浪潮。作为出身于Hip-hop圈的我，对这一点非常有共鸣。和他一起表演时，那种“想一起变得更强大”的感觉会很自然地涌现，所以我在那里喊出了他的名字。</p><p>————能感觉到每位艺人都怀着“由自己领跑，同时让BMSG整体更壮大”的意志。</p><p>是的。我觉得这是一个不断相互给予刺激、也从彼此那里获得刺激，从而成长的事务所。而最初掀起这股浪潮的毫无疑问是代表SKY-HI。正因为日高先生作为现役艺人始终站在最前线，不断思考新事物、创造有趣的动向，我、Shota、edhiii(boi)、REIKO才能不断重复“给予刺激、被刺激”的循环。我认为，日高先生作为现役艺人活跃在最前线，正是BMSG最大的财富。</p><h3 id="能实现比平时更高-分辨率-的创作——posse" tabindex="-1">能实现比平时更高“分辨率”的创作——POSSE <a class="header-anchor" href="#能实现比平时更高-分辨率-的创作——posse" aria-label="Permalink to &quot;能实现比平时更高“分辨率”的创作——POSSE&quot;">​</a></h3><p>————与日高先生一起进行POSSE活动，会带来哪些积极影响？</p><p>作为个人艺人，其实是要长时间直面孤独的。并不是没有可以商量的人，而是很多内心的迷惘，即使说出来也无法被解决，只能自己去面对，并把它们消化进作词作曲之中。而在POSSE里，以团队形式共享创作，可以分担这种孤独，也会激活以前没有用到的思考方式。有时会出现一些在自己个人作品中很难写出的歌词。在创作方式上，也可以从“既然是和这些成员一起，那就想做这样的东西”这样的角度去思考，从而实现比平时更高分辨率的表达，这一点非常有趣。</p><p>————11月还将首次举办全公司参与的企划“THE GAME CENTER”。</p><p>我觉得能够开展这种偏娱乐性质的企划，也是BMSG的魅力之一。以一种好的方式暂时关闭“艺人模式”，让包括粉丝在内的所有人都能在一些节点上一起热闹起来，我觉得这也是一种精神健康的体现，所以我很想尽情去享受。也希望自己能尽可能为团队做出贡献。我觉得大家全力去玩，才会变得有趣，所以也希望大家都能全力以赴（笑）！</p><p>————此外，第三个选秀“THE LAST PIECE”也正式启动了，你是如何看待这个选秀的？</p><p>作为BMSG的第一个阶段，这是最后一块拼图。从公司成立之初，日高先生就一直在说“要推出三个男团”。而且他也说过“第一个团体要登上东京巨蛋，并进行巨蛋巡演”“第二个团体也要达到Arena级别”，而这些如今都已经实现了。</p><p>第三个团体的成功，对于迎来五周年的BMSG整体的成功，以及对音乐圈的回馈等各方面来说，都会变得极其重要。不能只是某一个团体或某一个艺人特别成功就够了，而是要大家一起继续努力。</p><p>————你将于2025年2月11日举办首次Arena单独演唱会，作为BMSG最初的艺人之一，有怎样的决心？</p><p>我觉得，包括我在内，如今BMSG的个人艺人都有一个目标，那就是让大众说出“原来你也是BMSG的啊”。通过各自取得扎实的成绩、不断提升在音乐圈的影响力，从而让大家觉得“原来BMSG还有这样的艺人，挺有意思的”，我们正朝着这个方向成长。</p><p>我的Arena演出也是与这个愿景紧密相连的。作为一个融合了Hip-hop、Rock、Pop等多种基因的人，同时也是一个游走于主流与地下之间的人，我希望通过这次Arena演出，展现自己在音乐圈中的存在感。我会清晰地传达自己无类型、无边界的世界观，打造一场能够对整个音乐圈产生影响的演出。</p><blockquote><h3 id="from-sky-hi" tabindex="-1">from SKY-HI <a class="header-anchor" href="#from-sky-hi" aria-label="Permalink to &quot;from SKY-HI&quot;">​</a></h3><p>终于不再只是“年轻一代”的阶段了，也变得很可靠了。虽然不像从十几岁迈入二十岁那样变化剧烈，但周围看他的眼光也在发生变化，而Core并不是那种能够对此变得迟钝的人，所以我多少还是有点担心的。他责任感和野心都很强，我想他今后也会一边烦恼一边继续努力。不过我也希望能看到一个更加放松的Core，而且我相信一定能看到。我们最近正好也聊到了这个话题（笑）。</p></blockquote>',30)])])}const M=a(t,[["render",S]]);export{B as __pageData,M as default};
